from agents import Agent, handoff

fact_checker = Agent(
    name="FactChecker",
    instructions="Verify claims, return {valid: bool, evidence: str}",
    model="gpt-4o-mini"
)

response_agent = Agent(
    name="ResponseAgent",
    instructions="Generate natural voice responses only after fact-checking"
)

@response_agent.tool()
def check_facts(query: str):
    return handoff(fact_checker, query)

# Conversation memory
conversation_state = {"history": [], "max_turns": 10}

