from vex import Guardrail, verify

voice_guardrail = Guardrail(
    name="Voice Agent Safety",
    verifications=[
        "response_appropriateness",
        "latency_budget<500ms",
        "conversation_coherence",
        "safety_filter"
    ]
)

def safe_voice_pipeline(audio_input):
    raw_output = runner.run(audio_input)

    verified = verify(
        guardrail=voice_guardrail,
        input=conversation_state,
        output=raw_output
    )

    if verified:
        return tts_with_latency_guard(verified.output)
    else:
        return tts_with_latency_guard("I can't help with that.")
